import React, { useMemo, useState } from "react";

// ✅ Adjust these paths to match your project structure
import posterImg from "../../assets/poster.jpeg";
import libraryBg from "../../assets/library_bg.png";

export default function FilmLibrarySection() {
  const [query, setQuery] = useState("");
  const [activeFilter, setActiveFilter] = useState("Popular");

  const filters = ["Drama", "Documentary", "Short", "Country", "Popular"];

  const films = [
    { title: "Congo Killer Gorilla", available: true }, // active clickable
    { title: "Touki Bouki", available: false },
    { title: "Soleil Ô", available: false },
    { title: "Soleil Ô", available: false },
    { title: "Black Girl", available: false },
    { title: "Touki Bouki", available: false },
    { title: "Touki Bouki", available: false },
    { title: "Soleil Ô", available: false },
    { title: "Mandabi", available: false },
    { title: "Sambizanga", available: false },
  ];

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return films.filter((f) => (q ? f.title.toLowerCase().includes(q) : true));
  }, [films, query]);

  const handleActiveClick = () => {
    // ✅ For now: goes nowhere (later we’ll route / open modal)
  };

  return (
    <section className="filmLib" id="film-library">
      <div className="filmLib__bg" aria-hidden="true" />
      <div className="filmLib__vignette" aria-hidden="true" />

      <div className="filmLib__container">
        <header className="filmLib__header">
          <h2 className="filmLib__title">Film Library</h2>
          <p className="filmLib__subtitle">
            Licensed African films for one-time public screening.
          </p>
        </header>

        <div className="filmLib__controls">
          <div className="filmLib__search">
            <span className="filmLib__searchIcon">⌕</span>
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="filmLib__searchInput"
              placeholder="Search films..."
            />
          </div>

          <div className="filmLib__filters">
            {filters.map((f) => (
              <button
                key={f}
                type="button"
                className={
                  "filmLib__chip " + (activeFilter === f ? "isActive" : "")
                }
                onClick={() => setActiveFilter(f)}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        <div className="filmLib__grid">
          {filtered.map((film, idx) => {
            const isActive = film.available && idx === 0;

            return (
              <div className="filmLib__item" key={`${film.title}-${idx}`}>
                <button
                  type="button"
                  className={
                    "filmLib__posterBtn " +
                    (isActive ? "isClickable isGlow" : "isDisabled")
                  }
                  onClick={isActive ? handleActiveClick : undefined}
                  aria-disabled={!isActive}
                  title={isActive ? "Available" : "Not available"}
                >
                  <img
                    src={posterImg}
                    alt={film.title}
                    className="filmLib__posterImg"
                    draggable={false}
                  />

                  {!isActive && (
                    <div className="filmLib__posterOverlay">
                      <div className="filmLib__notAvail">
                        Currently not available for licensing
                      </div>
                    </div>
                  )}
                </button>

                {/* ✅ Title is OUTSIDE poster */}
                <div className="filmLib__filmTitle">{film.title}</div>
              </div>
            );
          })}
        </div>
      </div>

      <style>{`
        /* =========================
           SECTION LAYOUT (Fit 1 screen)
           ========================= */
        .filmLib{
          position: relative;
          width: 100%;
          min-height: 100vh;          /* ✅ fit within viewport */
          padding: 56px 18px 36px;    /* ✅ reduced vertical space */
          overflow: hidden;
          background: #000;
          display: flex;
          align-items: center;        /* ✅ centered vertically */
        }

        /* =========================
           BRIGHTER BACKGROUND
           ========================= */
        .filmLib__bg{
          position:absolute; inset:0;
          background-image: url(${libraryBg});
          background-size: cover;
          background-position: center;
          transform: scale(1.02);
          opacity: 1; /* ✅ full */
          filter: saturate(1.25) contrast(1.15) brightness(1.15); /* ✅ brighter */
        }
        .filmLib__vignette{
          position:absolute; inset:-2px;
          background:
            radial-gradient(900px 520px at 50% 18%, rgba(0,0,0,0.10), rgba(0,0,0,0.45)),
            radial-gradient(900px 520px at 50% 120%, rgba(0,0,0,0.18), rgba(0,0,0,0.60));
          pointer-events:none;
        }

        .filmLib__container{
          position: relative;
          max-width: 1180px;
          width: 100%;
          margin: 0 auto;
        }

        .filmLib__header{
          text-align: center;
          margin-bottom: 16px; /* ✅ tighter */
        }
        .filmLib__title{
          margin: 0;
          font-size: 46px;     /* ✅ smaller to fit */
          line-height: 1.05;
          font-weight: 800;
          color: rgba(255,255,255,0.92);
          text-shadow: 0 10px 40px rgba(0,0,0,0.55);
          letter-spacing: 0.3px;
        }
        .filmLib__subtitle{
          margin: 10px 0 0;
          font-size: 16px;     /* ✅ smaller */
          color: rgba(255,255,255,0.75);
          text-shadow: 0 10px 30px rgba(0,0,0,0.45);
        }

        /* =========================
           CONTROLS (tighter)
           ========================= */
        .filmLib__controls{
          display:flex;
          justify-content:center;
          gap: 14px;
          flex-wrap: wrap;
          margin: 14px auto 14px; /* ✅ tighter */
        }

        .filmLib__search{
          position: relative;
          display:flex;
          align-items:center;
          padding: 10px 14px 10px 38px;
          border-radius: 10px;
          border: 1px solid rgba(255, 165, 70, 0.28);
          background: rgba(0,0,0,0.30);
          box-shadow: 0 18px 55px rgba(0,0,0,0.35);
          min-width: 320px;
        }
        .filmLib__searchIcon{
          position:absolute;
          left: 12px;
          top: 50%;
          transform: translateY(-50%);
          color: rgba(255, 165, 70, 0.90);
          font-size: 16px;
          user-select: none;
        }
        .filmLib__searchInput{
          width: 100%;
          border: none;
          outline: none;
          background: transparent;
          color: rgba(255,255,255,0.92);
          font-size: 15px;
        }
        .filmLib__searchInput::placeholder{
          color: rgba(255,255,255,0.45);
        }

        .filmLib__filters{
          display:flex;
          gap: 10px;
          flex-wrap: wrap;
          padding: 10px;
          border-radius: 10px;
          border: 1px solid rgba(255, 165, 70, 0.22);
          background: rgba(0,0,0,0.22);
          box-shadow: 0 18px 55px rgba(0,0,0,0.28);
        }
        .filmLib__chip{
          cursor:pointer;
          border-radius: 9px;
          padding: 10px 14px;
          background: rgba(0,0,0,0.22);
          border: 1px solid rgba(255,165,70,0.22);
          color: rgba(255,255,255,0.82);
          font-weight: 700;
          font-size: 14px;
          transition: transform 160ms ease, border-color 160ms ease, background 160ms ease;
        }
        .filmLib__chip:hover{
          transform: translateY(-1px);
          border-color: rgba(255,165,70,0.42);
          background: rgba(0,0,0,0.30);
        }
        .filmLib__chip.isActive{
          border-color: rgba(255,165,70,0.72);
          background: rgba(255,165,70,0.12);
          color: rgba(255,255,255,0.95);
        }

        /* =========================
           GRID (fit in one screen)
           ========================= */
        .filmLib__grid{
          display:grid;
          grid-template-columns: repeat(5, minmax(0, 1fr));
          gap: 14px;           /* ✅ smaller gap */
          margin-top: 10px;    /* ✅ tighter */
        }

        .filmLib__item{
